function solve(words: string[]): number[] {
    const n = words.length;
    if (n === 0) return [];
    if (n === 1) return [0];

    // Compute LCP for adjacent pairs
    const lcpPairs: number[] = [];
    for (let i = 0; i < n - 1; i++) {
        lcpPairs.push(lcp(words[i], words[i + 1]));
    }

    // Compute prefix maxima
    const prefixMax: number[] = new Array(n - 1).fill(0);
    for (let i = 0; i < n - 1; i++) {
        prefixMax[i] = i === 0 ? lcpPairs[i] : Math.max(prefixMax[i - 1], lcpPairs[i]);
    }

    // Compute suffix maxima
    const suffixMax: number[] = new Array(n - 1).fill(0);
    for (let i = n - 2; i >= 0; i--) {
        suffixMax[i] = i === n - 2 ? lcpPairs[i] : Math.max(suffixMax[i + 1], lcpPairs[i]);
    }

    // Calculate answer for each index
    const answer: number[] = new Array(n).fill(0);
    for (let i = 0; i < n; i++) {
        let maxVal = 0;

        // Check max LCP before i
        if (i - 2 >= 0) {
            maxVal = Math.max(maxVal, prefixMax[i - 2]);
        }

        // Check max LCP after i
        if (i + 1 <= n - 2) {
            maxVal = Math.max(maxVal, suffixMax[i + 1]);
        }

        // Check new pair (i-1, i+1)
        if (i > 0 && i < n - 1) {
            const newLcp = lcp(words[i - 1], words[i + 1]);
            maxVal = Math.max(maxVal, newLcp);
        }

        answer[i] = maxVal;
    }

    return answer;
}

